import secrets
from cryptography.fernet import Fernet

def generate_key():
    return secrets.token_bytes(32)

def encrypt_credit_card(card_number):
    key = Fernet.generate_key()
    cipher_suite = Fernet(key)
    encrypted_card = cipher_suite.encrypt(card_number.encode())
    return key, encrypted_card

def decrypt_credit_card(encrypted_card, key):
    cipher_suite = Fernet(key)
    card_number = cipher_suite.decrypt(encrypted_card).decode()
    return card_number